import { useState } from "react";
import Login from "./components/Login";
import Chat from "./components/Chat";

function App() {
  const [user, setUser] = useState(localStorage.getItem("user"));

  return user ? <Chat user={user}/> : <Login setUser={setUser} />;
}

export default App;
